using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Threading.Tasks;

public class FileController : Controller
{
    private readonly string _baseDirectory = Path.Combine(Directory.GetCurrentDirectory(), "uploads");

    [HttpGet("files/{filename}")]
    public async Task<IActionResult> GetFile(string filename)
    {
        if (string.IsNullOrWhiteSpace(filename))
        {
            return BadRequest("Filename must be provided.");
        }

        // Canonicalize the path
        string filePath = Path.GetFullPath(Path.Combine(_baseDirectory, filename));

        // Validate the path
        if (!filePath.StartsWith(_baseDirectory) || Path.IsPathRooted(filename) || filename.Contains(".."))
        {
            return BadRequest("Invalid file path.");
        }

        if (!System.IO.File.Exists(filePath))
        {
            return NotFound("File not found.");
        }

        string contentType;
        new Microsoft.AspNetCore.StaticFiles.FileExtensionContentTypeProvider().TryGetContentType(filePath, out contentType);
        contentType = contentType ?? "application/octet-stream";

        var fileBytes = await System.IO.File.ReadAllBytesAsync(filePath);
        return File(fileBytes, contentType, Path.GetFileName(filePath));
    }
}